// Test the tmVar3 gene-links from civic-pubtator's report_PMC4150988.tsv
// A p.<AA><pos><AA2> call is only possible if the WT residue matches the protein sequence.
const targets = [
  { gene: 'OPRM1', acc: 'P35372', call: 'p.G13C', wt: 'G', pos: 13 },  // claimed by tmVar3
  { gene: 'KRAS',  acc: 'P01116', call: 'p.G13C', wt: 'G', pos: 13 },  // the plausible true gene
  { gene: 'KRAS',  acc: 'P01116', call: 'p.G12C', wt: 'G', pos: 12 },  // supp-only, 8 mentions
  { gene: 'RIT1',  acc: 'Q92963', call: 'p.M90I', wt: 'M', pos: 90 },  // paper's headline variant
  { gene: 'EGFR',  acc: 'P00533', call: 'p.L858R', wt: 'L', pos: 858 },
];
const out = [];
for (const t of targets) {
  const e = await api.get('/uniprotkb/{accession}', { accession: t.acc, fields: 'sequence,gene_names', format: 'json' });
  const seq = e.sequence?.value || '';
  const actual = seq[t.pos - 1] || '?';
  out.push({
    gene: t.gene, acc: t.acc, call: t.call, len: seq.length,
    wt_asserted: t.wt, residue_at_pos: actual,
    consistent: actual === t.wt,
  });
}
return out;

const CALLS = [{"gid":"10058","gene":"ABCB6","wt":"A","pos":692,"mut":"V"},{"gid":"113451","gene":"AZIN2","wt":"L","pos":74,"mut":"M"},{"gid":"113451","gene":"AZIN2","wt":"Q","pos":40,"mut":"L"},{"gid":"19","gene":"ABCA1","wt":"L","pos":597,"mut":"V"},{"gid":"1956","gene":"EGFR","wt":"L","pos":858,"mut":"R"},{"gid":"1956","gene":"EGFR","wt":"R","pos":45,"mut":"Q"},{"gid":"1956","gene":"EGFR","wt":"T","pos":790,"mut":"M"},{"gid":"1956","gene":"EGFR","wt":"V","pos":842,"mut":"I"}];
// Rebuild the full list from the two example reports would be huge; instead pull the distinct GENES
// and check EVERY call by streaming the gene IDs actually present.
const GENE_IDS = ["10058","113451","19","1956","207","208","238","240","2260","2261","2263","3265","3320","3845","369","4893","5290","5293","5604","5605","5728","5879","5894","6016","6098","6416","673","801","805","808","841","842","867","8503","861","4988","4914","7157"];

const acc = {}, seqs = {}, unmapped = [];
for (const gid of GENE_IDS) {
  try {
    const r = await api.get('/uniprotkb/search', {
      query: `(xref:geneid-${gid}) AND (organism_id:9606) AND (reviewed:true)`,
      fields: 'accession,sequence,gene_primary', format: 'json', size: 1,
    });
    const e = r.results?.[0];
    if (!e) { unmapped.push(gid); continue; }
    acc[gid] = { accession: e.primaryAccession, symbol: e.genes?.[0]?.geneName?.value };
    seqs[gid] = e.sequence?.value || '';
  } catch (err) { unmapped.push(gid + ':ERR'); }
}
return {
  mapped: Object.keys(seqs).length,
  unmapped,
  table: Object.entries(acc).map(([gid, a]) => ({ gid, symbol: a.symbol, accession: a.accession, len: seqs[gid].length })),
};

