tool_input.content:
/**
 * annot-verify — structural verification of civic-pubtator variant annotations.
 *
 * Takes a civic-pubtator `report_<pmid>.tsv` and adjudicates every protein
 * substitution call against the real protein sequence. A call `p.<WT><pos><MUT>`
 * is only possible if some isoform of the linked gene carries <WT> at <pos>.
 * Calls that survive are checked against CIViC to separate "already curated"
 * from "novel curation candidate".
 *
 * Pure logic + injectable fetchers, matching lib/{bio-graph,sysreview} convention.
 * Standalone: talks to UniProt + CIViC directly, so it runs without the MCP fleet.
 */

import { createHash } from "node:crypto";
import { readFileSync, writeFileSync, existsSync, mkdirSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const HERE = dirname(fileURLToPath(import.meta.url));

// ---------------------------------------------------------------- provenance

const sha256 = (s) => createHash("sha256").update(s).digest("hex");

function cite(source, url, payload, extra = {}) {
  return {
    source,
    url,
    retrieved_at: new Date().toISOString(),
    result_hash: sha256(typeof payload === "string" ? payload : JSON.stringify(payload)),
    ...extra,
  };
}

// -------------------------------------------------------------- pure parsing

/** civic-pubtator report columns, in order. */
const COLS = [
  "entity_category", "entity_type", "mention", "identifier",
  "identifier_name", "hgvs", "count", "doc_keys", "source",
];

export function parseReport(tsv) {
  const lines = tsv.split("\n").filter((l) => l.trim());
  return lines.slice(1).map((line) => {
    const cells = line.split("\t");
    const row = {};
    COLS.forEach((c, i) => (row[c] = cells[i] ?? ""));
    row.count = Number(row.count) || 0;
    row.docs = row.doc_keys ? row.doc_keys.split(",") : [];
    row.supplementary_only = row.docs.length > 0 && !row.docs.some((d) => d.startsWith("m"));
    return row;
  });
}

const PROTEIN_SUB = /^p\.([ACDEFGHIKLMNPQRSTVWY])(\d+)([ACDEFGHIKLMNPQRSTVWY])$/;

/** Returns {wt,pos,mut} for a simple missense call, else null. */
export function parseProteinSub(hgvs) {
  const m = PROTEIN_SUB.exec(hgvs ?? "");
  if (!m) return null;
  return { wt: m[1], pos: Number(m[2]), mut: m[3] };
}

/** Rows that are protein substitutions on a numeric NCBI Gene ID. */
export function checkableCalls(rows) {
  return rows.filter(
    (r) =>
      r.entity_category === "Variant" &&
      r.entity_type === "ProteinMutation" &&
      /^\d+$/.test(r.identifier) &&
      parseProteinSub(r.hgvs),
  );
}

// ------------------------------------------------------------- classification

export const VERDICT = {
  CONSISTENT_CANONICAL: "consistent_canonical",
  CONSISTENT_ISOFORM: "consistent_isoform_only",
  WT_EQ_MUT: "impossible_wt_equals_mut",
  OUT_OF_RANGE: "impossible_position_out_of_range",
  MISMATCH: "conflict_residue_mismatch",
  UNMAPPABLE: "unmappable_gene",
};

/** Verdicts that no isoform or numbering convention can rescue. */
export const STRUCTURALLY_IMPOSSIBLE = new Set([VERDICT.WT_EQ_MUT, VERDICT.OUT_OF_RANGE]);

/**
 * @param call {{wt,pos,mut}}
 * @param isoforms [{accession, sequence, canonical:boolean}]
 */
export function classify(call, isoforms) {
  if (!isoforms || isoforms.length === 0) {
    return { verdict: VERDICT.UNMAPPABLE, detail: "no reviewed human UniProt entry for this NCBI Gene ID" };
  }
  if (call.wt === call.mut) {
    return { verdict: VERDICT.WT_EQ_MUT, detail: `p.${call.wt}${call.pos}${call.mut} is not a substitution` };
  }

  const maxLen = Math.max(...isoforms.map((i) => i.sequence.length));
  if (call.pos > maxLen) {
    return {
      verdict: VERDICT.OUT_OF_RANGE,
      detail: `position ${call.pos} exceeds longest isoform (${maxLen} aa)`,
    };
  }

  const hits = isoforms.filter((i) => i.sequence[call.pos - 1] === call.wt);
  if (hits.length === 0) {
    const canon = isoforms.find((i) => i.canonical) ?? isoforms[0];
    const actual = canon.sequence[call.pos - 1] ?? "?";
    return {
      verdict: VERDICT.MISMATCH,
      detail: `no isoform has ${call.wt} at ${call.pos}; canonical ${canon.accession} has ${actual}`,
    };
  }
  const canonHit = hits.find((i) => i.canonical);
  return canonHit
    ? { verdict: VERDICT.CONSISTENT_CANONICAL, detail: canonHit.accession }
    : {
        verdict: VERDICT.CONSISTENT_ISOFORM,
        detail: `matches non-canonical isoform ${hits.map((h) => h.accession).join(",")} only`,
      };
}

// ------------------------------------------------------------------ fetchers

/** Parse a UniProt FASTA bundle into isoform records. */
export function parseFasta(text) {
  const out = [];
  for (const block of text.split("\n>")) {
    const chunk = block.startsWith(">") ? block.slice(1) : block;
    const [header, ...seqLines] = chunk.split("\n");
    if (!header?.trim()) continue;
    const accession = header.split("|")[1];
    if (!accession) continue;
    out.push({
      accession,
      canonical: !accession.includes("-"),
      sequence: seqLines.join("").replace(/\s/g, ""),
    });
  }
  return out.filter((i) => i.sequence.length > 0);
}

export function makeUniProtFetcher({ fetchImpl = fetch, cachePath } = {}) {
  const cache = cachePath && existsSync(cachePath) ? JSON.parse(readFileSync(cachePath, "utf8")) : {};
  const citations = [];

  const get = async (geneId) => {
    if (cache[geneId]) return cache[geneId];
    const q = `(xref:geneid-${geneId}) AND (organism_id:9606) AND (reviewed:true)`;
    const url =
      `https://rest.uniprot.org/uniprotkb/search?query=${encodeURIComponent(q)}` +
      `&format=fasta&includeIsoform=true&size=25`;
    const res = await fetchImpl(url);
    if (!res.ok) throw new Error(`UniProt ${res.status} for gene ${geneId}`);
    const text = await res.text();
    citations.push(cite("UniProt", url, text, { gene_id: geneId }));
    cache[geneId] = parseFasta(text);
    if (cachePath) writeFileSync(cachePath, JSON.stringify(cache));
    return cache[geneId];
  };
  return { get, citations };
}

export function makeCivicFetcher({ fetchImpl = fetch, cachePath } = {}) {
  const cache = cachePath && existsSync(cachePath) ? JSON.parse(readFileSync(cachePath, "utf8")) : {};
  const citations = [];
  const ENDPOINT = "https://civicdb.org/api/graphql";
  const QUERY = `query($feature:String,$variant:String){
    browseVariants(featureName:$feature, variantName:$variant, first:5){
      nodes { id name feature { name } }
    }
  }`;

  const get = async (gene, variantName) => {
    const key = `${gene}:${variantName}`;
    if (cache[key]) return cache[key];
    const body = JSON.stringify({ query: QUERY, variables: { feature: gene, variant: variantName } });
    const res = await fetchImpl(ENDPOINT, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body,
    });
    if (!res.ok) throw new Error(`CIViC ${res.status} for ${key}`);
    const json = await res.json();
    citations.push(cite("CIViC", ENDPOINT, json, { query: key }));
    const nodes = json?.data?.browseVariants?.nodes ?? [];
    // Require the feature to actually match — browseVariants does substring matching.
    const exact = nodes.filter(
      (n) => n.feature?.name?.toUpperCase() === gene.toUpperCase() &&
             n.name?.toUpperCase() === variantName.toUpperCase(),
    );
    cache[key] = exact.map((n) => ({ id: n.id, name: n.name }));
    if (cachePath) writeFileSync(cachePath, JSON.stringify(cache));
    return cache[key];
  };
  return { get, citations };
}

// ------------------------------------------------------------------ pipeline

export async function verifyReport(rows, { uniprot, civic, onProgress } = {}) {
  const calls = checkableCalls(rows);
  const results = [];

  // Stage 1 — structural verification against every isoform.
  const geneIds = [...new Set(calls.map((c) => c.identifier))];
  const isoformsById = {};
  for (const gid of geneIds) {
    try {
      isoformsById[gid] = await uniprot.get(gid);
    } catch {
      isoformsById[gid] = [];
    }
    onProgress?.(`uniprot ${gid} → ${isoformsById[gid].length} isoform(s)`);
  }

  for (const row of calls) {
    const sub = parseProteinSub(row.hgvs);
    const { verdict, detail } = classify(sub, isoformsById[row.identifier]);
    results.push({ row, sub, verdict, detail, in_civic: null, civic_ids: [] });
  }

  // Stage 2 — CIViC novelty, only for calls that survived stage 1.
  if (civic) {
    const survivors = results.filter(
      (r) => r.verdict === VERDICT.CONSISTENT_CANONICAL || r.verdict === VERDICT.CONSISTENT_ISOFORM,
    );
    const seen = new Map();
    for (const r of survivors) {
      const gene = r.row.identifier_name;
      const vName = `${r.sub.wt}${r.sub.pos}${r.sub.mut}`;
      const key = `${gene}:${vName}`;
      if (!seen.has(key)) {
        try {
          seen.set(key, await civic.get(gene, vName));
        } catch {
          seen.set(key, null);
        }
        onProgress?.(`civic ${key} → ${seen.get(key)?.length ?? "err"}`);
      }
      const hit = seen.get(key);
      r.in_civic = hit === null ? null : hit.length > 0;
      r.civic_ids = hit?.map((h) => h.id) ?? [];
    }
  }
  return results;
}

// ------------------------------------------------------------------ summarize

export function summarize(results) {
  const byVerdict = {};
  const mentionsByVerdict = {};
  for (const r of results) {
    byVerdict[r.verdict] = (byVerdict[r.verdict] ?? 0) + 1;
    mentionsByVerdict[r.verdict] = (mentionsByVerdict[r.verdict] ?? 0) + r.row.count;
  }
  const total = results.length;
  const impossible = results.filter((r) => STRUCTURALLY_IMPOSSIBLE.has(r.verdict)).length;
  const survivors = results.filter(
    (r) => r.verdict === VERDICT.CONSISTENT_CANONICAL || r.verdict === VERDICT.CONSISTENT_ISOFORM,
  );
  const novel = survivors.filter((r) => r.in_civic === false);
  const known = survivors.filter((r) => r.in_civic === true);

  return {
    total_calls: total,
    unique_calls: new Set(results.map((r) => `${r.row.identifier}:${r.row.hgvs}`)).size,
    by_verdict: byVerdict,
    mentions_by_verdict: mentionsByVerdict,
    structurally_impossible: impossible,
    pct_structurally_impossible: total ? +((100 * impossible) / total).toFixed(1) : 0,
    survivors: survivors.length,
    pct_survivors: total ? +((100 * survivors.length) / total).toFixed(1) : 0,
    already_in_civic: known.length,
    novel_curation_candidates: novel.length,
    novel_supplementary_only: novel.filter((r) => r.row.supplementary_only).length,
    novel_list: [...new Set(novel.map((r) => `${r.row.identifier_name} ${r.row.hgvs}`))].sort(),
  };
}

export function toTsv(results) {
  const head = [...COLS, "verdict", "detail", "in_civic", "civic_variant_ids", "supplementary_only"];
  const lines = [head.join("\t")];
  for (const r of results) {
    lines.push(
      [
        ...COLS.map((c) => r.row[c]),
        r.verdict,
        r.detail,
        r.in_civic === null ? "unknown" : String(r.in_civic),
        r.civic_ids.join("|"),
        String(r.row.supplementary_only),
      ].join("\t"),
    );
  }
  return lines.join("\n") + "\n";
}

// ----------------------------------------------------------------------- cli

async function main() {
  const reports = process.argv.slice(2);
  if (reports.length === 0) {
    console.error("usage: node verify.mjs <report_PMID.tsv> [...]");
    process.exit(1);
  }
  const outDir = join(HERE, "out");
  mkdirSync(outDir, { recursive: true });

  const uniprot = makeUniProtFetcher({ cachePath: join(outDir, ".uniprot-cache.json") });
  const civic = makeCivicFetcher({ cachePath: join(outDir, ".civic-cache.json") });

  const all = {};
  for (const path of reports) {
    const name = path.split("/").pop().replace(/^report_|\.tsv$/g, "");
    process.stderr.write(`\n── ${name} ──\n`);
    const rows = parseReport(readFileSync(path, "utf8"));
    const results = await verifyReport(rows, {
      uniprot,
      civic,
      onProgress: (m) => process.stderr.write(`  ${m}\n`),
    });
    writeFileSync(join(outDir, `verified_${name}.tsv`), toTsv(results));
    all[name] = summarize(results);
  }

  const manifest = {
    generated_at: new Date().toISOString(),
    tool: "annot-verify",
    inputs: reports,
    per_report: all,
    citations: {
      uniprot: uniprot.citations.length,
      civic: civic.citations.length,
      sample: [uniprot.citations[0], civic.citations[0]].filter(Boolean),
    },
  };
  writeFileSync(join(outDir, "summary.json"), JSON.stringify(manifest, null, 2));
  console.log(JSON.stringify(all, null, 2));
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  await main();
}

