const UNIPROT = "https://rest.uniprot.org/uniprotkb";

/**
 * Every isoform, not just the canonical one.
 *
 * `includeIsoform=true` on the search/stream endpoints silently returns only the
 * canonical sequence. Checking a call against the canonical alone produces false
 * accusations: EZH2 p.Y646F is a real variant on isoform Q15910-2 (751 aa), while
 * canonical Q15910 (746 aa) has Y at 641 and I at 646. Isoform IDs must be read
 * from the entry's ALTERNATIVE PRODUCTS comment and fetched individually.
 */
export function makeUniProtFetcher({ fetchImpl = fetch, cachePath } = {}) {
  const cache = readCache(cachePath);
  const citations = [];

  const seqOf = async (acc) => {
    const url = `${UNIPROT}/${acc}.fasta`;
    const res = await fetchImpl(url);
    if (!res.ok) return null;
    const text = await res.text();
    citations.push(cite("UniProt", url, text, { accession: acc }));
    return text.split("\n").slice(1).join("").replace(/\s/g, "");
  };

  const get = async (geneId) => {
    if (cache[geneId]) return cache[geneId];

    const q = `(xref:geneid-${geneId}) AND (organism_id:9606) AND (reviewed:true)`;
    const sUrl = `${UNIPROT}/search?query=${encodeURIComponent(q)}&fields=accession&format=json&size=1`;
    const sRes = await fetchImpl(sUrl);
    if (!sRes.ok) throw new Error(`UniProt search ${sRes.status} for gene ${geneId}`);
    const sJson = await sRes.json();
    citations.push(cite("UniProt", sUrl, sJson, { gene_id: geneId }));

    const accession = sJson.results?.[0]?.primaryAccession;
    if (!accession) {
      cache[geneId] = [];
      if (cachePath) writeFileSync(cachePath, JSON.stringify(cache));
      return cache[geneId];
    }

    const eUrl = `${UNIPROT}/${accession}.json?fields=cc_alternative_products`;
    const eRes = await fetchImpl(eUrl);
    const eJson = eRes.ok ? await eRes.json() : {};
    const isoformIds = (eJson.comments ?? []).flatMap((c) =>
      (c.isoforms ?? []).flatMap((i) => i.isoformIds ?? []),
    );

    const wanted = [accession, ...isoformIds.filter((id) => id !== accession)];
    const isoforms = [];
    const seenSeq = new Set();
    for (const acc of wanted) {
      const sequence = await seqOf(acc);
      if (!sequence || seenSeq.has(sequence)) continue;
      seenSeq.add(sequence);
      isoforms.push({ accession: acc, sequence, canonical: acc === accession });
    }
    // The base accession's sequence == isoform -1; keep exactly one canonical flag.
    if (!isoforms.some((i) => i.canonical) && isoforms.length > 0) isoforms[0].canonical = true;

    cache[geneId] = isoforms;
    if (cachePath) writeFileSync(cachePath, JSON.stringify(cache));
    return isoforms;
  };
  return { get, citations };
}

