export function makeCivicFetcher({ fetchImpl = fetch, cachePath } = {}) {
  const cache = readCache(cachePath);
  const citations = [];
  const ENDPOINT = "https://civicdb.org/api/graphql";
  const QUERY = `query($feature:String,$variant:String){
    browseVariants(featureName:$feature, variantName:$variant, first:25){
      nodes { id name featureName }
    }
  }`;

  const get = async (gene, variantName) => {
    const key = `${gene}:${variantName}`;
    if (cache[key]) return cache[key];
    const body = JSON.stringify({ query: QUERY, variables: { feature: gene, variant: variantName } });
    const res = await fetchImpl(ENDPOINT, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body,
    });
    if (!res.ok) throw new Error(`CIViC HTTP ${res.status} for ${key}`);
    const json = await res.json();
    // A GraphQL error yields data:null. Defaulting that to [] would report every
    // variant as absent from CIViC — an unverified negative masquerading as a fact.
    if (json.errors?.length) {
      throw new Error(`CIViC GraphQL error for ${key}: ${json.errors[0].message}`);
    }
    citations.push(cite("CIViC", ENDPOINT, json, { query: key }));
    const nodes = json.data?.browseVariants?.nodes ?? [];
    // browseVariants matches on substrings; require an exact feature+variant match.
    const exact = nodes.filter(
      (n) =>
        n.featureName?.toUpperCase() === gene.toUpperCase() &&
        n.name?.toUpperCase() === variantName.toUpperCase(),
    );
    cache[key] = exact.map((n) => ({ id: n.id, name: n.name }));
    if (cachePath) writeFileSync(cachePath, JSON.stringify(cache));
    return cache[key];
  };

  /**
   * Positive control. If a variant CIViC certainly holds comes back empty, the
   * query contract has drifted and every "novel" verdict this run would be a lie.
   */
  const canary = async () => {
    const hits = await get("BRAF", "V600E");
    if (hits.length === 0) {
      throw new Error("CIViC canary failed: BRAF V600E returned no hits — refusing to emit novelty verdicts");
    }
    return hits;
  };

  return { get, canary, citations };
}

