const known = survivors.filter((r) => r.in_civic === true);
const unresolved = survivors.filter((r) => r.in_civic === null);

/**
 * A residue check passes on luck as often as on truth.
 *
 * MAP2K1 yields 47 `p.H<pos><M|F>` calls; 46 sit beyond the 393-aa protein and are
 * plainly table-parsing debris. The 47th, p.H358M, happens to land in range on a
 * histidine. Judged alone it looks like a novel missense variant. Judged next to
 * its 46 siblings it is obviously the same artifact. So: when a gene emits a run of
 * same-(wt→mut) calls and several are positionally impossible, the survivors are
 * guilty by association. This is a heuristic, not a proof — hence a soft verdict.
 */
export function flagArtifactFamilies(results, { minFamily = 3, minImpossible = 2, minRatio = 0.4 } = {}) {
  const families = new Map();
  for (const r of results) {
    const key = `${r.row.identifier}|${r.sub.wt}>${r.sub.mut}`;
    if (!families.has(key)) families.set(key, []);
    families.get(key).push(r);
  }
  for (const members of families.values()) {
    if (members.length < minFamily) continue;
    const bad = members.filter((m) => m.verdict === VERDICT.OUT_OF_RANGE).length;
    if (bad < minImpossible || bad / members.length < minRatio) continue;
    for (const m of members) {
      if (m.verdict === VERDICT.CONSISTENT_CANONICAL || m.verdict === VERDICT.CONSISTENT_ISOFORM) {
        m.original_verdict = m.verdict;
        m.verdict = VERDICT.ARTIFACT_FAMILY;
        m.detail = `${bad}/${members.length} sibling ${m.sub.wt}→${m.sub.mut} calls on this gene are position-impossible`;
      }
    }
  }
  return results;
}

