/**
 * Fixture checks for annot-verify's pure logic. Run: node checks.mjs
 * Deliberately NOT named *.test.mjs — root vitest globs that pattern and would
 * fail on a node:assert suite.
 */
import assert from "node:assert/strict";
import {
  parseProteinSub, classify, parseFasta, flagArtifactFamilies, VERDICT,
} from "./verify.mjs";

const iso = (accession, sequence, canonical = false) => ({ accession, sequence, canonical });
let n = 0;
const ok = (name, fn) => { fn(); n++; console.log(`  ok  ${name}`); };

ok("parses a simple missense call", () => {
  assert.deepEqual(parseProteinSub("p.G12C"), { wt: "G", pos: 12, mut: "C" });
});

ok("rejects indels and malformed HGVS", () => {
  for (const h of ["p.ELREA746del", "c.270G>T", "p.Q79,40L", "", "G12C"]) {
    assert.equal(parseProteinSub(h), null, h);
  }
});

ok("accepts a call matching the canonical sequence", () => {
  // KRAS-like: G at position 12.
  const r = classify({ wt: "G", pos: 12, mut: "C" }, [iso("P01116", "MTEYKLVVVGAGGVGKSALTIQ", true)]);
  assert.equal(r.verdict, VERDICT.CONSISTENT_CANONICAL);
});

ok("rejects a call whose wild-type residue is absent (OPRM1 p.G13C)", () => {
  // OPRM1 position 13 is a cysteine, so G13C cannot exist there.
  const seq = "MDSSAAPTNASNCTDA"; // C at index 12 => position 13
  const r = classify({ wt: "G", pos: 13, mut: "C" }, [iso("P35372", seq, true)]);
  assert.equal(r.verdict, VERDICT.MISMATCH);
  assert.match(r.detail, /has C/);
});

ok("rejects positions beyond the longest isoform (MAP2K1 p.H3255F)", () => {
  const r = classify({ wt: "H", pos: 3255, mut: "F" }, [iso("Q02750", "MPKKKPTPIQ", true)]);
  assert.equal(r.verdict, VERDICT.OUT_OF_RANGE);
});

ok("rejects wt == mut (p.H157H is not a substitution)", () => {
  const r = classify({ wt: "H", pos: 2, mut: "H" }, [iso("X", "AHC", true)]);
  assert.equal(r.verdict, VERDICT.WT_EQ_MUT);
});

ok("rescues a real variant numbered on a minor isoform (EZH2 p.Y646F)", () => {
  // canonical has I at 646; isoform-2 has Y at 646.
  const canon = iso("Q15910", "A".repeat(645) + "I" + "A".repeat(100), true);
  const alt = iso("Q15910-2", "A".repeat(645) + "Y" + "A".repeat(105));
  const r = classify({ wt: "Y", pos: 646, mut: "F" }, [canon, alt]);
  assert.equal(r.verdict, VERDICT.CONSISTENT_ISOFORM);
  assert.match(r.detail, /Q15910-2/);
});

ok("reports unmappable genes rather than guessing", () => {
  assert.equal(classify({ wt: "A", pos: 1, mut: "T" }, []).verdict, VERDICT.UNMAPPABLE);
});

ok("parses multi-record FASTA and flags the canonical accession", () => {
  const f = ">sp|P01116|RASK_HUMAN x\nMTEY\nKLVV\n>sp|P01116-2|RASK_HUMAN y\nMTEYK\n";
  const parsed = parseFasta(f);
  assert.equal(parsed.length, 2);
  assert.equal(parsed[0].sequence, "MTEYKLVV");
  assert.equal(parsed[0].canonical, true);
  assert.equal(parsed[1].canonical, false);
});

ok("suppresses an in-range survivor sitting in a run of impossible siblings", () => {
  const mk = (pos, verdict) => ({
    row: { identifier: "5604", identifier_name: "MAP2K1", hgvs: `p.H${pos}M` },
    sub: { wt: "H", pos, mut: "M" },
    verdict,
  });
  const results = [
    mk(358, VERDICT.CONSISTENT_CANONICAL),
    mk(1299, VERDICT.OUT_OF_RANGE),
    mk(1355, VERDICT.OUT_OF_RANGE),
    mk(2444, VERDICT.OUT_OF_RANGE),
  ];
  flagArtifactFamilies(results);
  assert.equal(results[0].verdict, VERDICT.ARTIFACT_FAMILY);
  assert.equal(results[0].original_verdict, VERDICT.CONSISTENT_CANONICAL);
});

ok("leaves a lone legitimate call untouched (KRAS p.G12C has no impossible siblings)", () => {
  const results = [{
    row: { identifier: "3845", identifier_name: "KRAS", hgvs: "p.G12C" },
    sub: { wt: "G", pos: 12, mut: "C" },
    verdict: VERDICT.CONSISTENT_CANONICAL,
  }];
  flagArtifactFamilies(results);
  assert.equal(results[0].verdict, VERDICT.CONSISTENT_CANONICAL);
});

console.log(`\n${n} checks passed`);

