tool_input.content:
/**
 * Annotation verification — shared types.
 *
 * The core question: a civic-pubtator (or LLM) annotation claims a protein
 * substitution `p.<WT><pos><MUT>` on some gene. That call is only *possible* if
 * an isoform of the gene actually carries `<WT>` at `<pos>`. These types model
 * the calls, the adjudication verdicts, and the two injectable fetchers that
 * bring in ground truth (protein isoforms + CIViC curation status).
 */

/** One row of a civic-pubtator `report_<pmid>.tsv`, parsed. */
export interface ReportRow {
	entity_category: string;
	entity_type: string;
	mention: string;
	/** NCBI Gene ID for variant rows (numeric string), or upstream identifier. */
	identifier: string;
	identifier_name: string;
	/** HGVS-ish protein string, e.g. `p.G12C`. */
	hgvs: string;
	count: number;
	doc_keys: string;
	source: string;
	/** Parsed `doc_keys`: `m*` = main text, `s*` = supplementary. */
	docs: string[];
	/** True when every occurrence is in a supplementary file (never main text). */
	supplementary_only: boolean;
}

/** A parsed simple missense call. */
export interface ProteinSub {
	wt: string;
	pos: number;
	mut: string;
}

/** One protein isoform sequence. */
export interface Isoform {
	accession: string;
	sequence: string;
	canonical: boolean;
}

/** A CIViC variant that matches a gene + variant name exactly. */
export interface CivicHit {
	id: number;
	name: string;
}

/**
 * Re-checkable attribution for a fetched upstream response. Same field shape as
 * the fleet's `_meta.citation`, so a fetcher wired to the MCP servers can pass
 * the fleet's citation straight through, while the standalone HTTP fetchers
 * mint their own.
 */
export interface Citation {
	source: string;
	url: string;
	retrieved_at: string;
	/** sha256 of the canonicalized response bytes. */
	result_hash: string;
	[extra: string]: unknown;
}

/** The adjudication outcomes for a single call. */
export const VERDICT = {
	CONSISTENT_CANONICAL: "consistent_canonical",
	CONSISTENT_ISOFORM: "consistent_isoform_only",
	WT_EQ_MUT: "impossible_wt_equals_mut",
	OUT_OF_RANGE: "impossible_position_out_of_range",
	MISMATCH: "conflict_residue_mismatch",
	UNMAPPABLE: "unmappable_gene",
	ARTIFACT_FAMILY: "suspect_artifact_family",
} as const;

export type Verdict = (typeof VERDICT)[keyof typeof VERDICT];

/** Verdicts that no isoform or numbering convention can rescue. */
export const STRUCTURALLY_IMPOSSIBLE: ReadonlySet<Verdict> = new Set([
	VERDICT.WT_EQ_MUT,
	VERDICT.OUT_OF_RANGE,
]);

/** A call after structural + novelty adjudication. */
export interface VerifiedCall {
	row: ReportRow;
	sub: ProteinSub;
	verdict: Verdict;
	detail: string;
	/** Set when a stronger verdict was demoted (e.g. by the artifact-family pass). */
	original_verdict?: Verdict;
	/** true = in CIViC, false = novel, null = lookup not performed/failed. */
	in_civic: boolean | null;
	civic_ids: number[];
}

/** Brings in every isoform sequence for an NCBI Gene ID (with provenance). */
export interface IsoformFetcher {
	get(geneId: string): Promise<Isoform[]>;
	readonly citations: Citation[];
}

/** Reports whether CIViC curates an exact gene + variant-name pair. */
export interface CivicFetcher {
	get(gene: string, variantName: string): Promise<CivicHit[]>;
	/** Positive control; throws if a certainly-present variant returns empty. */
	canary(): Promise<CivicHit[]>;
	readonly citations: Citation[];
}

/**
 * Pure parsing — civic-pubtator report rows, protein-substitution HGVS, and
 * UniProt FASTA. No I/O, no network; every function is total and synchronous.
 */

import type { ProteinSub, ReportRow, Isoform } from "./types";

/** civic-pubtator report columns, in order. */
const COLS = [
	"entity_category",
	"entity_type",
	"mention",
	"identifier",
	"identifier_name",
	"hgvs",
	"count",
	"doc_keys",
	"source",
] as const;

/** Parse a whole `report_<pmid>.tsv` into typed rows. */
export function parseReport(tsv: string): ReportRow[] {
	const lines = tsv.split("\n").filter((l) => l.trim());
	return lines.slice(1).map((line) => {
		const cells = line.split("\t");
		const get = (i: number) => cells[i] ?? "";
		const docs = get(7) ? get(7).split(",") : [];
		return {
			entity_category: get(0),
			entity_type: get(1),
			mention: get(2),
			identifier: get(3),
			identifier_name: get(4),
			hgvs: get(5),
			count: Number(get(6)) || 0,
			doc_keys: get(7),
			source: get(8),
			docs,
			supplementary_only: docs.length > 0 && !docs.some((d) => d.startsWith("m")),
		};
	});
}

const PROTEIN_SUB = /^p\.([ACDEFGHIKLMNPQRSTVWY])(\d+)([ACDEFGHIKLMNPQRSTVWY])$/;

/** Returns `{wt,pos,mut}` for a simple missense call, else `null`. */
export function parseProteinSub(hgvs: string | undefined): ProteinSub | null {
	const m = PROTEIN_SUB.exec(hgvs ?? "");
	if (!m) return null;
	return { wt: m[1], pos: Number(m[2]), mut: m[3] };
}

/** Rows that are protein substitutions on a numeric NCBI Gene ID. */
export function checkableCalls(rows: ReportRow[]): ReportRow[] {
	return rows.filter(
		(r) =>
			r.entity_category === "Variant" &&
			r.entity_type === "ProteinMutation" &&
			/^\d+$/.test(r.identifier) &&
			parseProteinSub(r.hgvs) !== null,
	);
}

/** Parse a UniProt FASTA bundle into isoform records. */
export function parseFasta(text: string): Isoform[] {
	const out: Isoform[] = [];
	for (const block of text.split("\n>")) {
		const chunk = block.startsWith(">") ? block.slice(1) : block;
		const [header, ...seqLines] = chunk.split("\n");
		if (!header?.trim()) continue;
		const accession = header.split("|")[1];
		if (!accession) continue;
		out.push({
			accession,
			canonical: !accession.includes("-"),
			sequence: seqLines.join("").replace(/\s/g, ""),
		});
	}
	return out.filter((i) => i.sequence.length > 0);
}

/**
 * Pure adjudication logic. Two passes, both synchronous and side-effect-free:
 *
 *   1. `classify` — judge one call against every isoform of its gene.
 *   2. `flagArtifactFamilies` — demote in-range survivors that sit inside a run
 *      of position-impossible siblings (a residue check passes on luck as often
 *      as on truth).
 */

import type { Isoform, ProteinSub, VerifiedCall } from "./types";
import { VERDICT } from "./types";

/**
 * Judge a single call against every isoform of the linked gene.
 *
 * A call `p.<WT><pos><MUT>` is only possible if some isoform carries `<WT>` at
 * `<pos>`. Matching the canonical sequence is a stronger claim than matching a
 * minor isoform only, so the two are separated (EZH2 p.Y646F is real on isoform
 * Q15910-2 but not on the canonical 746-aa form).
 */
export function classify(
	call: ProteinSub,
	isoforms: Isoform[] | undefined,
): { verdict: (typeof VERDICT)[keyof typeof VERDICT]; detail: string } {
	if (!isoforms || isoforms.length === 0) {
		return {
			verdict: VERDICT.UNMAPPABLE,
			detail: "no reviewed human UniProt entry for this NCBI Gene ID",
		};
	}
	if (call.wt === call.mut) {
		return {
			verdict: VERDICT.WT_EQ_MUT,
			detail: `p.${call.wt}${call.pos}${call.mut} is not a substitution`,
		};
	}

	const maxLen = Math.max(...isoforms.map((i) => i.sequence.length));
	if (call.pos > maxLen) {
		return {
			verdict: VERDICT.OUT_OF_RANGE,
			detail: `position ${call.pos} exceeds longest isoform (${maxLen} aa)`,
		};
	}

	const hits = isoforms.filter((i) => i.sequence[call.pos - 1] === call.wt);
	if (hits.length === 0) {
		const canon = isoforms.find((i) => i.canonical) ?? isoforms[0];
		const actual = canon.sequence[call.pos - 1] ?? "?";
		return {
			verdict: VERDICT.MISMATCH,
			detail: `no isoform has ${call.wt} at ${call.pos}; canonical ${canon.accession} has ${actual}`,
		};
	}
	const canonHit = hits.find((i) => i.canonical);
	return canonHit
		? { verdict: VERDICT.CONSISTENT_CANONICAL, detail: canonHit.accession }
		: {
				verdict: VERDICT.CONSISTENT_ISOFORM,
				detail: `matches non-canonical isoform ${hits.map((h) => h.accession).join(",")} only`,
			};
}

/**
 * A residue check passes on luck as often as on truth.
 *
 * MAP2K1 yields 47 `p.H<pos><M|F>` calls; 46 sit beyond the 393-aa protein and
 * are plainly table-parsing debris. The 47th, p.H358M, happens to land in range
 * on a histidine — judged alone it looks like a novel missense variant, judged
 * next to its 46 siblings it is obviously the same artifact. When a gene emits a
 * run of same-(wt→mut) calls and several are positionally impossible, the
 * survivors are guilty by association. Heuristic, not proof — hence a soft,
 * reversible verdict that records what it demoted.
 */
export function flagArtifactFamilies(
	results: VerifiedCall[],
	opts: { minFamily?: number; minImpossible?: number; minRatio?: number } = {},
): VerifiedCall[] {
	const { minFamily = 3, minImpossible = 2, minRatio = 0.4 } = opts;
	const families = new Map<string, VerifiedCall[]>();
	for (const r of results) {
		const key = `${r.row.identifier}|${r.sub.wt}>${r.sub.mut}`;
		const bucket = families.get(key);
		if (bucket) bucket.push(r);
		else families.set(key, [r]);
	}
	for (const members of families.values()) {
		if (members.length < minFamily) continue;
		const bad = members.filter((m) => m.verdict === VERDICT.OUT_OF_RANGE).length;
		if (bad < minImpossible || bad / members.length < minRatio) continue;
		for (const m of members) {
			if (
				m.verdict === VERDICT.CONSISTENT_CANONICAL ||
				m.verdict === VERDICT.CONSISTENT_ISOFORM
			) {
				m.original_verdict = m.verdict;
				m.verdict = VERDICT.ARTIFACT_FAMILY;
				m.detail = `${bad}/${members.length} sibling ${m.sub.wt}→${m.sub.mut} calls on this gene are position-impossible`;
			}
		}
	}
	return results;
}

/**
 * Orchestration + reporting. The pure logic lives in `parse`/`classify`; this
 * module threads the two injectable fetchers through it and shapes the output.
 *
 * Wire it to the standalone HTTP fetchers (`./fetchers`) for a zero-dependency
 * run, or to fleet-backed fetchers (uniprot_api_execute / civic) so every
 * upstream read carries the fleet's `_meta.citation` natively.
 */

import { checkableCalls, parseProteinSub } from "./parse";
import { classify, flagArtifactFamilies } from "./classify";
import type {
	CivicFetcher,
	IsoformFetcher,
	ReportRow,
	VerifiedCall,
} from "./types";
import { STRUCTURALLY_IMPOSSIBLE, VERDICT } from "./types";

export interface VerifyOptions {
	uniprot: IsoformFetcher;
	/** Omit to skip CIViC novelty adjudication (structural verdicts only). */
	civic?: CivicFetcher;
	onProgress?: (message: string) => void;
}

/**
 * Structural verification (stage 1) followed by CIViC novelty (stage 2).
 * Stage 2 runs only for calls that survive stage 1, and only after a canary
 * proves the CIViC contract still holds — an empty result from a broken query
 * must never be reported as "novel".
 */
export async function verifyReport(
	rows: ReportRow[],
	{ uniprot, civic, onProgress }: VerifyOptions,
): Promise<VerifiedCall[]> {
	const calls = checkableCalls(rows);
	const results: VerifiedCall[] = [];

	// Stage 1 — structural verification against every isoform.
	const geneIds = [...new Set(calls.map((c) => c.identifier))];
	const isoformsById = new Map<string, Awaited<ReturnType<IsoformFetcher["get"]>>>();
	for (const gid of geneIds) {
		try {
			isoformsById.set(gid, await uniprot.get(gid));
		} catch {
			isoformsById.set(gid, []);
		}
		onProgress?.(`uniprot ${gid} → ${isoformsById.get(gid)?.length ?? 0} isoform(s)`);
	}

	for (const row of calls) {
		const sub = parseProteinSub(row.hgvs);
		if (!sub) continue; // unreachable: checkableCalls guarantees a parse
		const { verdict, detail } = classify(sub, isoformsById.get(row.identifier));
		results.push({ row, sub, verdict, detail, in_civic: null, civic_ids: [] });
	}

	// Stage 1b — suppress in-range survivors that belong to an artifact run.
	flagArtifactFamilies(results);

	// Stage 2 — CIViC novelty, only for calls that survived stage 1.
	if (civic) {
		await civic.canary(); // fail loudly rather than declare everything novel
		const survivors = results.filter(
			(r) =>
				r.verdict === VERDICT.CONSISTENT_CANONICAL ||
				r.verdict === VERDICT.CONSISTENT_ISOFORM,
		);
		const seen = new Map<string, Awaited<ReturnType<CivicFetcher["get"]>> | null>();
		for (const r of survivors) {
			const gene = r.row.identifier_name;
			const vName = `${r.sub.wt}${r.sub.pos}${r.sub.mut}`;
			const key = `${gene}:${vName}`;
			if (!seen.has(key)) {
				try {
					seen.set(key, await civic.get(gene, vName));
				} catch {
					seen.set(key, null);
				}
				onProgress?.(`civic ${key} → ${seen.get(key)?.length ?? "err"}`);
			}
			const hit = seen.get(key);
			r.in_civic = hit == null ? null : hit.length > 0;
			r.civic_ids = hit?.map((h) => h.id) ?? [];
		}
	}
	return results;
}

export interface VerifySummary {
	total_calls: number;
	unique_calls: number;
	by_verdict: Record<string, number>;
	mentions_by_verdict: Record<string, number>;
	structurally_impossible: number;
	pct_structurally_impossible: number;
	survivors: number;
	pct_survivors: number;
	already_in_civic: number;
	civic_lookup_unresolved: number;
	novel_curation_candidates: number;
	novel_supplementary_only: number;
	known_list: string[];
	/** Survived on the canonical sequence — high-confidence curation candidates. */
	novel_canonical: string[];
	/** Survived on a minor isoform only — weaker, needs numbering adjudication. */
	novel_isoform_only_needs_adjudication: string[];
}

const isSurvivor = (r: VerifiedCall) =>
	r.verdict === VERDICT.CONSISTENT_CANONICAL || r.verdict === VERDICT.CONSISTENT_ISOFORM;

const label = (r: VerifiedCall) => `${r.row.identifier_name} ${r.row.hgvs}`;
const uniqSort = (rs: VerifiedCall[]) => [...new Set(rs.map(label))].sort();

export function summarize(results: VerifiedCall[]): VerifySummary {
	const byVerdict: Record<string, number> = {};
	const mentionsByVerdict: Record<string, number> = {};
	for (const r of results) {
		byVerdict[r.verdict] = (byVerdict[r.verdict] ?? 0) + 1;
		mentionsByVerdict[r.verdict] = (mentionsByVerdict[r.verdict] ?? 0) + r.row.count;
	}
	const total = results.length;
	const impossible = results.filter((r) => STRUCTURALLY_IMPOSSIBLE.has(r.verdict)).length;
	const survivors = results.filter(isSurvivor);
	const novel = survivors.filter((r) => r.in_civic === false);
	const known = survivors.filter((r) => r.in_civic === true);
	const unresolved = survivors.filter((r) => r.in_civic === null);
	// Matching only a minor isoform is a weaker claim than the canonical sequence.
	const tier = (v: VerifiedCall["verdict"]) => (v: VerifiedCall) =>
		(v as unknown) === undefined;
	const canonical = novel.filter(
		(r) => (r.original_verdict ?? r.verdict) === VERDICT.CONSISTENT_CANONICAL,
	);
	const isoformOnly = novel.filter(
		(r) => (r.original_verdict ?? r.verdict) === VERDICT.CONSISTENT_ISOFORM,
	);
	void tier;

	return {
		total_calls: total,
		unique_calls: new Set(results.map((r) => `${r.row.identifier}:${r.row.hgvs}`)).size,
		by_verdict: byVerdict,
		mentions_by_verdict: mentionsByVerdict,
		structurally_impossible: impossible,
		pct_structurally_impossible: total ? +((100 * impossible) / total).toFixed(1) : 0,
		survivors: survivors.length,
		pct_survivors: total ? +((100 * survivors.length) / total).toFixed(1) : 0,
		already_in_civic: known.length,
		civic_lookup_unresolved: unresolved.length,
		novel_curation_candidates: novel.length,
		novel_supplementary_only: novel.filter((r) => r.row.supplementary_only).length,
		known_list: uniqSort(known),
		novel_canonical: uniqSort(canonical),
		novel_isoform_only_needs_adjudication: uniqSort(isoformOnly),
	};
}

const TSV_COLS = [
	"entity_category",
	"entity_type",
	"mention",
	"identifier",
	"identifier_name",
	"hgvs",
	"count",
	"doc_keys",
	"source",
] as const;

/** Re-emit the report with verdict columns appended (curator worklist). */
export function toTsv(results: VerifiedCall[]): string {
	const head = [
		...TSV_COLS,
		"verdict",
		"detail",
		"in_civic",
		"civic_variant_ids",
		"supplementary_only",
	];
	const lines = [head.join("\t")];
	for (const r of results) {
		lines.push(
			[
				...TSV_COLS.map((c) => String(r.row[c] ?? "")),
				r.verdict,
				r.detail,
				r.in_civic === null ? "unknown" : String(r.in_civic),
				r.civic_ids.join("|"),
				String(r.row.supplementary_only),
			].join("\t"),
		);
	}
	return `${lines.join("\n")}\n`;
}

