/**
 * Standalone HTTP fetchers — a zero-dependency way to run the verifier without
 * the MCP fleet (this is what a collaborator like the Griffith Lab would use).
 *
 * When wired into the fleet instead, replace these with thin adapters over
 * `uniprot_api_execute` / the CIViC tools; those already attach the fleet's
 * `_meta.citation`, so the `citations` arrays here become pass-throughs.
 *
 * Two hazards are handled explicitly, both learned the hard way:
 *   - UniProt `includeIsoform=true` silently returns only the canonical
 *     sequence, so isoform IDs are read from ALTERNATIVE PRODUCTS and fetched
 *     one by one. A canonical-only check falsely accuses EZH2 p.Y646F.
 *   - A CIViC GraphQL error yields `data:null`; defaulting that to `[]` reports
 *     every variant as novel. The fetcher throws on `errors` and ships a canary.
 */

import { parseFasta } from "./parse";
import type { Citation, CivicFetcher, CivicHit, Isoform, IsoformFetcher } from "./types";

type FetchImpl = typeof fetch;

/** Stable stringify (sorted keys) so a citation hash is reproducible. */
function canonical(value: unknown): string {
	if (value === null || typeof value !== "object") return JSON.stringify(value);
	if (Array.isArray(value)) return `[${value.map(canonical).join(",")}]`;
	const obj = value as Record<string, unknown>;
	const keys = Object.keys(obj).sort();
	return `{${keys.map((k) => `${JSON.stringify(k)}:${canonical(obj[k])}`).join(",")}}`;
}

async function sha256Hex(input: string): Promise<string> {
	const bytes = new TextEncoder().encode(input);
	const digest = await crypto.subtle.digest("SHA-256", bytes);
	return [...new Uint8Array(digest)].map((b) => b.toString(16).padStart(2, "0")).join("");
}

async function cite(
	source: string,
	url: string,
	payload: unknown,
	extra: Record<string, unknown> = {},
): Promise<Citation> {
	return {
		source,
		url,
		retrieved_at: new Date().toISOString(),
		result_hash: await sha256Hex(typeof payload === "string" ? payload : canonical(payload)),
		...extra,
	};
}

const UNIPROT = "https://rest.uniprot.org/uniprotkb";

export function makeUniProtFetcher(
	{ fetchImpl = fetch }: { fetchImpl?: FetchImpl } = {},
): IsoformFetcher {
	const cache = new Map<string, Isoform[]>();
	const citations: Citation[] = [];

	const seqOf = async (acc: string): Promise<string | null> => {
		const url = `${UNIPROT}/${acc}.fasta`;
		const res = await fetchImpl(url);
		if (!res.ok) return null;
		const text = await res.text();
		citations.push(await cite("UniProt", url, text, { accession: acc }));
		return text.split("\n").slice(1).join("").replace(/\s/g, "");
	};

	const get = async (geneId: string): Promise<Isoform[]> => {
		const cached = cache.get(geneId);
		if (cached) return cached;

		const q = `(xref:geneid-${geneId}) AND (organism_id:9606) AND (reviewed:true)`;
		const sUrl = `${UNIPROT}/search?query=${encodeURIComponent(q)}&fields=accession&format=json&size=1`;
		const sRes = await fetchImpl(sUrl);
		if (!sRes.ok) throw new Error(`UniProt search ${sRes.status} for gene ${geneId}`);
		const sJson = (await sRes.json()) as { results?: { primaryAccession?: string }[] };
		citations.push(await cite("UniProt", sUrl, sJson, { gene_id: geneId }));

		const accession = sJson.results?.[0]?.primaryAccession;
		if (!accession) {
			cache.set(geneId, []);
			return [];
		}

		const eUrl = `${UNIPROT}/${accession}.json?fields=cc_alternative_products`;
		const eRes = await fetchImpl(eUrl);
		const eJson = eRes.ok
			? ((await eRes.json()) as {
					comments?: { isoforms?: { isoformIds?: string[] }[] }[];
				})
			: {};
		const isoformIds = (eJson.comments ?? []).flatMap((c) =>
			(c.isoforms ?? []).flatMap((i) => i.isoformIds ?? []),
		);

		const wanted = [accession, ...isoformIds.filter((id) => id !== accession)];
		const isoforms: Isoform[] = [];
		const seenSeq = new Set<string>();
		for (const acc of wanted) {
			const sequence = await seqOf(acc);
			if (!sequence || seenSeq.has(sequence)) continue;
			seenSeq.add(sequence);
			isoforms.push({ accession: acc, sequence, canonical: acc === accession });
		}
		if (!isoforms.some((i) => i.canonical) && isoforms.length > 0) {
			isoforms[0].canonical = true;
		}
		cache.set(geneId, isoforms);
		return isoforms;
	};

	return { get, citations };
}

const CIVIC_ENDPOINT = "https://civicdb.org/api/graphql";
const CIVIC_QUERY = `query($feature:String,$variant:String){
  browseVariants(featureName:$feature, variantName:$variant, first:25){
    nodes { id name featureName }
  }
}`;

export function makeCivicFetcher(
	{ fetchImpl = fetch }: { fetchImpl?: FetchImpl } = {},
): CivicFetcher {
	const cache = new Map<string, CivicHit[]>();
	const citations: Citation[] = [];

	const get = async (gene: string, variantName: string): Promise<CivicHit[]> => {
		const key = `${gene}:${variantName}`;
		const cached = cache.get(key);
		if (cached) return cached;

		const body = JSON.stringify({
			query: CIVIC_QUERY,
			variables: { feature: gene, variant: variantName },
		});
		const res = await fetchImpl(CIVIC_ENDPOINT, {
			method: "POST",
			headers: { "Content-Type": "application/json" },
			body,
		});
		if (!res.ok) throw new Error(`CIViC HTTP ${res.status} for ${key}`);
		const json = (await res.json()) as {
			errors?: { message: string }[];
			data?: { browseVariants?: { nodes?: { id: number; name: string; featureName: string }[] } };
		};
		// A GraphQL error yields data:null. Defaulting that to [] would report
		// every variant as absent from CIViC — an unverified negative as fact.
		if (json.errors?.length) {
			throw new Error(`CIViC GraphQL error for ${key}: ${json.errors[0].message}`);
		}
		citations.push(await cite("CIViC", CIVIC_ENDPOINT, json, { query: key }));
		const nodes = json.data?.browseVariants?.nodes ?? [];
		// browseVariants matches on substrings; require an exact feature+variant match.
		const exact = nodes.filter(
			(n) =>
				n.featureName?.toUpperCase() === gene.toUpperCase() &&
				n.name?.toUpperCase() === variantName.toUpperCase(),
		);
		const hits = exact.map((n) => ({ id: n.id, name: n.name }));
		cache.set(key, hits);
		return hits;
	};

	const canary = async (): Promise<CivicHit[]> => {
		const hits = await get("BRAF", "V600E");
		if (hits.length === 0) {
			throw new Error(
				"CIViC canary failed: BRAF V600E returned no hits — refusing to emit novelty verdicts",
			);
		}
		return hits;
	};

	return { get, canary, citations };
}

/**
 * Annotation verification core — the public surface.
 *
 * Adjudicates civic-pubtator (or LLM-emitted) protein-substitution annotations
 * against ground truth: a call `p.<WT><pos><MUT>` is only possible if an isoform
 * of the linked gene carries `<WT>` at `<pos>`. Survivors are checked against
 * CIViC to separate *already curated* from *novel curation candidate*. Same
 * shape as the other `@bio-mcp/evidence` cores — pure logic plus injectable,
 * provenance-bearing fetchers; no Worker/server wiring here.
 *
 * Standalone (zero-dependency, for external collaborators):
 *   import { verifyReport, summarize, makeUniProtFetcher, makeCivicFetcher }
 *     from "@bio-mcp/evidence/annot-verify";
 *   const rows = parseReport(await readFile("report_PMID.tsv", "utf8"));
 *   const results = await verifyReport(rows, {
 *     uniprot: makeUniProtFetcher(),
 *     civic: makeCivicFetcher(),
 *   });
 *   console.log(summarize(results));
 *
 * Fleet-wired: swap the two fetchers for thin adapters over uniprot_api_execute
 * and the CIViC tools — each upstream read then carries `_meta.citation` natively.
 */

export type {
	ReportRow,
	ProteinSub,
	Isoform,
	CivicHit,
	Citation,
	Verdict,
	VerifiedCall,
	IsoformFetcher,
	CivicFetcher,
} from "./types";
export { VERDICT, STRUCTURALLY_IMPOSSIBLE } from "./types";

export { parseReport, parseProteinSub, checkableCalls, parseFasta } from "./parse";
export { classify, flagArtifactFamilies } from "./classify";

export type { VerifyOptions, VerifySummary } from "./verify";
export { verifyReport, summarize, toTsv } from "./verify";

export { makeUniProtFetcher, makeCivicFetcher } from "./fetchers";

import { describe, expect, it } from "vitest";
import {
	checkableCalls,
	classify,
	flagArtifactFamilies,
	parseFasta,
	parseProteinSub,
	parseReport,
	summarize,
	toTsv,
	VERDICT,
	type Isoform,
	type VerifiedCall,
} from "./index";

const iso = (accession: string, sequence: string, canonical = false): Isoform => ({
	accession,
	sequence,
	canonical,
});

describe("parseProteinSub", () => {
	it("parses a simple missense call", () => {
		expect(parseProteinSub("p.G12C")).toEqual({ wt: "G", pos: 12, mut: "C" });
	});

	it("rejects indels, DNA, and malformed HGVS", () => {
		for (const h of ["p.ELREA746del", "c.270G>T", "p.Q79,40L", "", "G12C", undefined]) {
			expect(parseProteinSub(h as string)).toBeNull();
		}
	});
});

describe("classify", () => {
	it("accepts a call matching the canonical sequence", () => {
		const r = classify({ wt: "G", pos: 12, mut: "C" }, [iso("P01116", "MTEYKLVVVGAGGVGKSALTIQ", true)]);
		expect(r.verdict).toBe(VERDICT.CONSISTENT_CANONICAL);
	});

	it("rejects a call whose wild-type residue is absent (OPRM1 p.G13C)", () => {
		// OPRM1 position 13 is a cysteine, so G13C cannot exist there.
		const r = classify({ wt: "G", pos: 13, mut: "C" }, [iso("P35372", "MDSSAAPTNASNC", true)]);
		expect(r.verdict).toBe(VERDICT.MISMATCH);
		expect(r.detail).toMatch(/has C/);
	});

	it("rejects positions beyond the longest isoform (MAP2K1 p.H3255F)", () => {
		const r = classify({ wt: "H", pos: 3255, mut: "F" }, [iso("Q02750", "MPKKKPTPIQ", true)]);
		expect(r.verdict).toBe(VERDICT.OUT_OF_RANGE);
	});

	it("rejects wt == mut (p.H157H is not a substitution)", () => {
		const r = classify({ wt: "H", pos: 2, mut: "H" }, [iso("X", "AHC", true)]);
		expect(r.verdict).toBe(VERDICT.WT_EQ_MUT);
	});

	it("rescues a real variant numbered on a minor isoform (EZH2 p.Y646F)", () => {
		// canonical has I at 646; isoform-2 has Y at 646.
		const canon = iso("Q15910", `${"A".repeat(645)}I${"A".repeat(100)}`, true);
		const alt = iso("Q15910-2", `${"A".repeat(645)}Y${"A".repeat(105)}`);
		const r = classify({ wt: "Y", pos: 646, mut: "F" }, [canon, alt]);
		expect(r.verdict).toBe(VERDICT.CONSISTENT_ISOFORM);
		expect(r.detail).toMatch(/Q15910-2/);
	});

	it("reports unmappable genes rather than guessing", () => {
		expect(classify({ wt: "A", pos: 1, mut: "T" }, []).verdict).toBe(VERDICT.UNMAPPABLE);
	});
});

describe("parseFasta", () => {
	it("parses multi-record FASTA and flags the canonical accession", () => {
		const f = ">sp|P01116|RASK_HUMAN x\nMTEY\nKLVV\n>sp|P01116-2|RASK_HUMAN y\nMTEYK\n";
		const parsed = parseFasta(f);
		expect(parsed).toHaveLength(2);
		expect(parsed[0].sequence).toBe("MTEYKLVV");
		expect(parsed[0].canonical).toBe(true);
		expect(parsed[1].canonical).toBe(false);
	});
});

describe("flagArtifactFamilies", () => {
	const mk = (pos: number, verdict: VerifiedCall["verdict"]): VerifiedCall => ({
		row: {
			entity_category: "Variant",
			entity_type: "ProteinMutation",
			mention: "",
			identifier: "5604",
			identifier_name: "MAP2K1",
			hgvs: `p.H${pos}M`,
			count: 1,
			doc_keys: "s2",
			source: "tmVar3",
			docs: ["s2"],
			supplementary_only: true,
		},
		sub: { wt: "H", pos, mut: "M" },
		verdict,
		detail: "",
		in_civic: null,
		civic_ids: [],
	});

	it("suppresses an in-range survivor sitting in a run of impossible siblings", () => {
		const results = [
			mk(358, VERDICT.CONSISTENT_CANONICAL),
			mk(1299, VERDICT.OUT_OF_RANGE),
			mk(1355, VERDICT.OUT_OF_RANGE),
			mk(2444, VERDICT.OUT_OF_RANGE),
		];
		flagArtifactFamilies(results);
		expect(results[0].verdict).toBe(VERDICT.ARTIFACT_FAMILY);
		expect(results[0].original_verdict).toBe(VERDICT.CONSISTENT_CANONICAL);
	});

	it("leaves a lone legitimate call untouched", () => {
		const results = [mk(358, VERDICT.CONSISTENT_CANONICAL)];
		flagArtifactFamilies(results);
		expect(results[0].verdict).toBe(VERDICT.CONSISTENT_CANONICAL);
	});
});

describe("report parsing + summary", () => {
	const tsv = [
		"entity_category\tentity_type\tmention\tidentifier\tidentifier_name\thgvs\tcount\tdoc_keys\tsource",
		"Variant\tProteinMutation\tG12C\t3845\tKRAS\tp.G12C\t8\ts2\ttmVar3",
		"Variant\tProteinMutation\tG12V\t3845\tKRAS\tp.G12V\t3\tm1,s1\ttmVar3",
		"Gene\tGene\tKRAS\t3845\tKRAS\t\t5\tm1\tgnorm2",
	].join("\n");

	it("parses rows and flags supplementary-only mentions", () => {
		const rows = parseReport(tsv);
		expect(rows).toHaveLength(3);
		expect(rows[0].supplementary_only).toBe(true); // s2 only
		expect(rows[1].supplementary_only).toBe(false); // has m1
	});

	it("keeps only checkable protein-substitution calls", () => {
		const rows = parseReport(tsv);
		expect(checkableCalls(rows)).toHaveLength(2); // the Gene row drops out
	});

	it("summarize partitions verdicts and separates novel tiers", () => {
		const results: VerifiedCall[] = parseReport(tsv)
			.filter((r) => r.entity_category === "Variant")
			.map((row) => ({
				row,
				sub: parseProteinSub(row.hgvs)!,
				verdict: VERDICT.CONSISTENT_CANONICAL,
				detail: "P01116",
				in_civic: row.hgvs === "p.G12C" ? true : false,
				civic_ids: row.hgvs === "p.G12C" ? [12] : [],
			}));
		const s = summarize(results);
		expect(s.survivors).toBe(2);
		expect(s.already_in_civic).toBe(1);
		expect(s.novel_curation_candidates).toBe(1);
		expect(s.novel_canonical).toEqual(["KRAS p.G12V"]);
		expect(toTsv(results)).toMatch(/verdict\tdetail\tin_civic/);
	});
});

