}

const CIVIC_ENDPOINT = "https://civicdb.org/api/graphql";
const CIVIC_QUERY = `query($feature:String,$variant:String){
  browseVariants(featureName:$feature, variantName:$variant, first:25){
    nodes { id name featureName }
  }
}`;

export function makeCivicFetcher(
	{ fetchImpl = runtime.fetch }: { fetchImpl?: FetchLike } = {},
): CivicFetcher {
	const cache = new Map<string, CivicHit[]>();
	const citations: Citation[] = [];

	const get = async (gene: string, variantName: string): Promise<CivicHit[]> => {
		const key = `${gene}:${variantName}`;
		const cached = cache.get(key);
		if (cached) return cached;

		const body = JSON.stringify({
			query: CIVIC_QUERY,
			variables: { feature: gene, variant: variantName },
		});
		const res = await fetchImpl(CIVIC_ENDPOINT, {
			method: "POST",
			headers: { "Content-Type": "application/json" },
			body,
		});
		if (!res.ok) throw new Error(`CIViC HTTP ${res.status} for ${key}`);
		const json = (await res.json()) as {
			errors?: { message: string }[];
			data?: { browseVariants?: { nodes?: { id: number; name: string; featureName: string }[] } };
		};
		// A GraphQL error yields data:null. Defaulting that to [] would report
		// every variant as absent from CIViC — an unverified negative as fact.
		if (json.errors?.length) {
			throw new Error(`CIViC GraphQL error for ${key}: ${json.errors[0].message}`);
		}
		citations.push(await cite("CIViC", CIVIC_ENDPOINT, json, { query: key }));
		const nodes = json.data?.browseVariants?.nodes ?? [];
		// browseVariants matches on substrings; require an exact feature+variant match.
		const exact = nodes.filter(
			(n) =>
				n.featureName?.toUpperCase() === gene.toUpperCase() &&
				n.name?.toUpperCase() === variantName.toUpperCase(),
		);
		const hits = exact.map((n) => ({ id: n.id, name: n.name }));
		cache.set(key, hits);
		return hits;
	};

	const canary = async (): Promise<CivicHit[]> => {
		const hits = await get("BRAF", "V600E");
		if (hits.length === 0) {
			throw new Error(
				"CIViC canary failed: BRAF V600E returned no hits — refusing to emit novelty verdicts",
			);
		}
		return hits;
	};

	return { get, canary, citations };
}

/**
 * Parity check: run the graduated @bio-mcp/evidence/annot-verify core (live
 * fetchers) against the two real example reports and confirm it reproduces the
 * numbers the validated scratch .mjs produced. Guards against a port regression.
 */
import { readFileSync } from "node:fs";
import {
	parseReport,
	verifyReport,
	summarize,
	makeUniProtFetcher,
	makeCivicFetcher,
} from "@bio-mcp/evidence/annot-verify";

const reports = ["data/report_PMC4150988.tsv", "data/report_PMC3210554.tsv"];
const uniprot = makeUniProtFetcher();
const civic = makeCivicFetcher();

let calls = 0, impossible = 0, survivors = 0, known = 0, novel = 0, canon = 0, iso = 0;
for (const path of reports) {
	const rows = parseReport(readFileSync(new URL(path, import.meta.url), "utf8"));
	const results = await verifyReport(rows, {
		uniprot,
		civic,
		onProgress: () => {},
	});
	const s = summarize(results);
	calls += s.total_calls;
	impossible += s.structurally_impossible;
	survivors += s.survivors;
	known += s.already_in_civic;
	novel += s.novel_curation_candidates;
	canon += s.novel_canonical.length;
	iso += s.novel_isoform_only_needs_adjudication.length;
	console.error(`${path.split("/").pop()}: calls=${s.total_calls} impossible=${s.structurally_impossible} survivors=${s.survivors} known=${s.already_in_civic} novel=${s.novel_curation_candidates}`);
}

const got = { calls, impossible, survivors, known, novel, canon, iso };
const want = { calls: 369, impossible: 113, survivors: 95, known: 40, novel: 55, canon: 39, iso: 15 };
const ok = JSON.stringify(got) === JSON.stringify(want);
console.log(JSON.stringify({ got, want, PARITY: ok }, null, 2));
process.exit(ok ? 0 : 1);

